function PlayerCard({ player }) {
  return (
    <div style={{ border: "1px solid #ddd", padding: 10, margin: 10 }}>
      <h4>{player.name}</h4>
      <p>Team: {player.team}</p>
      <p>Role: {player.role}</p>
      <p>Runs: {player.runs} | Wickets: {player.wickets}</p>
    </div>
  );
}

export default PlayerCard;
